18	/**
19	  Discriminant for {@linkcode Ok} and {@linkcode Err} variants of the
20	  {@linkcode Result} type.
21	
22	  You can use the discriminant via the `variant` property of `Result` instances
23	  if you need to match explicitly on it.
24	 */
25	export const Variant = {
26	  Ok: 'Ok',
27	  Err: 'Err',
28	} as const;
29	
30	export type Variant = keyof typeof Variant;
31	
32	/** Representation of an {@linkcode Ok} when serialized to JSON. */
33	export interface OkJSON<T> {
34	  variant: 'Ok';
35	  value: T;
36	}
37	
38	/** Representation of an {@linkcode Err} when serialized to JSON. */
