95	    For constructing a `Task` from an existing `Promise`, see:
96	
97	    - {@linkcode fromPromise}
98	    - {@linkcode safelyTry}
99	    - {@linkcode tryOr}
100	    - {@linkcode tryOrElse}
101	
102	    For constructing a `Task` immediately resolved or rejected with given
103	    values, see {@linkcode Task.resolve} and {@linkcode Task.reject}
104	    respectively.
105	
106	    @param executor A function which the constructor will execute to manage
107	      the lifecycle of the `Task`. The executor in turn has two functions as
108	      parameters: one to call on resolution, the other on rejection.
109	   */
110	  constructor(executor: (resolve: (value: T) => void, reject: (reason: E) => void) => void) {
111	    this.#promise = new Promise<Result<T, E>>((resolve) => {
112	      executor(
113	        (value) => {
114	          this.#state = [State.Resolved, value];
